// Compute SHA-256 of the artifact payload
const crypto = require('crypto');

const body = $json.body;
const artifactPayload = JSON.stringify({
  artifact_id: body.artifact_id,
  artifact_type: body.artifact_type,
  creator_id: body.creator_id,
  receipt_id: body.receipt_id,
  consent_tokens: body.consent_tokens || []
});

const payloadSha256 = crypto.createHash('sha256').update(artifactPayload).digest('hex');

return [
  {
    json: {
      ...body,
      payload_sha256: payloadSha256,
      artifact_payload_raw: artifactPayload
    }
  }
];

// Build ProvenanceManifest JSON matching /schemas/ProvenanceManifest.schema.json
const crypto = require('crypto');
const data = $json;

const manifest = {
  schema_version: "1.0.0",
  manifest_id: `manifest-${crypto.randomUUID()}`,
  created_at: new Date().toISOString(),
  producer: {
    system: "NOIZY.ai / n8n Provenance Signer",
    version: "1.0.0",
    environment: "dev"
  },
  artifact: {
    artifact_id: data.artifact_id,
    type: data.artifact_type || "mixed",
    title: data.artifact_title || undefined,
    format: data.artifact_format || undefined
  },
  integrity: {
    payload_sha256: data.payload_sha256,
    lineage_hash: "pending"
  },
  rights: {
    consent_required: true,
    royalty_rule: "75_25",
    allowed_uses: data.allowed_uses || [],
    blocked_uses: data.blocked_uses || []
  },
  attribution: {
    primary_creator: {
      actor_id: data.creator_id,
      display_name: data.creator_name || data.creator_id
    },
    source_contributions: (data.consent_tokens || []).map(token => ({
      contributor_id: token.creator_id || data.creator_id,
      asset_ref: token.asset_ref || data.artifact_id,
      consent_token_ref: token.token_id || token
    }))
  },
  links: {
    receipt_id: data.receipt_id || "pending"
  },
  signature: {
    algo: "ed25519",
    public_key_ref: "pending",
    signature_b64: "pending",
    signed_canonical_json_sha256: "pending"
  }
};

return [{ json: manifest }];

// Compute canonical JSON hash for signing
// This creates a deterministic hash of the manifest (excluding the signature field)
const crypto = require('crypto');
const manifest = { ...$json };

// Remove the signature block before computing the canonical hash
const { signature, ...manifestWithoutSig } = manifest;

// Sort keys for canonical JSON
const canonicalJson = JSON.stringify(manifestWithoutSig, Object.keys(manifestWithoutSig).sort());
const canonicalHash = crypto.createHash('sha256').update(canonicalJson).digest('hex');

// Also compute lineage_hash from the integrity-relevant fields
const lineagePayload = JSON.stringify({
  artifact_id: manifest.artifact.artifact_id,
  payload_sha256: manifest.integrity.payload_sha256,
  creator_id: manifest.attribution.primary_creator.actor_id,
  contributions: manifest.attribution.source_contributions.map(c => c.consent_token_ref).sort()
});
const lineageHash = crypto.createHash('sha256').update(lineagePayload).digest('hex');

// Update manifest with computed hashes
manifest.integrity.lineage_hash = lineageHash;
manifest.signature.signed_canonical_json_sha256 = canonicalHash;

return [{ json: manifest }];

